// E2e tests for category: embeddings
package e2e_test

import (
	"encoding/json"
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"

	kreuzberg "github.com/kreuzberg-dev/kreuzberg/v4"
)

func Test_EmbeddingDisabled(t *testing.T) {
	// Tests chunking without embeddings - chunks should not have embedding vectors
	var config kreuzberg.ExtractionConfig
	if err := json.Unmarshal([]byte(`{"chunking":{"max_chars":500,"max_overlap":50}}`), &config); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	result, err := kreuzberg.ExtractFileSync(`pdf/fake_memo.pdf`, nil, config)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	if strings.TrimSpace(result.MimeType) != `application/pdf` {
		t.Errorf("equals mismatch: got %v", result.MimeType)
	}
	assert.GreaterOrEqual(t, len(result.Content), 10, "expected length >= 10")
	if result.Chunks != nil {
		assert.GreaterOrEqual(t, len(*result.Chunks), 1, "expected at least 1 elements")
	}
	assert.True(t, func() bool {
		chunks := result.Chunks
		if chunks == nil {
			return false
		}
		for _, c := range *chunks {
			if c.Content == "" {
				return false
			}
		}
		return true
	}(), "expected true")
}
